import React, { useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';


const Purchases = () => {
  const [purchase, setPurchase] = useState([]);
 
    
  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [purchaseResponse, vendorResponse] = await Promise.all([
        fetch('http://localhost:8081/purchasesAPI').then((response) => response.json()),
      ]);
  
      setPurchase(purchaseResponse);
    } catch (error) {
      console.log('Error fetching data:', error);
    }
  };
  
  const handleAdd = useCallback((newPurchase) => {

    fetch('http://localhost:8081/purchasesAPI', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newPurchase),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding material');
        }
      })
      .then(() => {
        fetchData();
      })
      .catch((error) => {
        console.log('Error adding material:', error);
      });
  }, [purchase]);  

  const handleDelete = useCallback((deletedPurchase) => {
    const confirmDeletion = window.confirm('Are you sure you want to delete this material?');

    if (confirmDeletion) {
      fetch(`http://localhost:8081/purchasesAPI/${deletedPurchase.id}`, {
        method: 'DELETE',
      })
        .then((response) => response.json())
        .then((data) => {
          const updatedPurchaseList = purchase.filter((m) => m.id !== deletedMPurchase.id);
          setPurchase(updatedPurchaseList);
        })
        .catch((error) => {
          console.log('Error deleting material:', error);
        });
    }
  }, [purchase]);

  const handleEdit = useCallback((purchase) => {
    if (editingPurchase && editingPurchase.id === purchase.id) {
      alert('Purchase is already being edited.');
      return;
    }

    setEditingPurchase(purchase);
  }, [editingPurchase]);



  const handleUpdate = useCallback((updatedPurchase) => {
    
    fetch(`http://localhost:8081/purchasesAPI/${updatedPurchase.id}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(updatedPurchase),
    })
      .then((response) => response.json())
      .then((data) => {
        const updatedPurchaseList = purchase.map((m) =>
          m.matid === updatedPurchase.id ? updatedPurchase : m
        );
        setPurchase(updatedPurchaseList);
        setEditingPurchase(null);

        
      })
      .catch((error) => {
        console.log('Error updating purchase:', error);
      });
  }, [purchase]);

  

  const columns = React.useMemo(
    () => [
      { Header: 'Purchase ID', accessor: 'id' },
      { Header: 'Location', accessor: 'location' },
      { Header: 'Material ID', accessor: 'materialid' },
      { Header: 'Quantity', accessor: 'quantity' },
      {
        Header: 'Price/UoM',
        accessor: 'price_per_unit',
        Cell: ({ value }) => {
          const formattedValue = `${value} €`;
          return <span>{formattedValue}</span>;
        },
      },
      { Header: 'Recent Vendor',
      accessor: 'recent_vendor',
      Cell: ({ value }) => {
        const vendor = vendors.find((vendor) => vendor.vendorid === value);
        const vendorName = vendor ? vendor.name : '';

        return (
          <a href={`http://localhost:8081/vendors/${value}`} target="_blank" rel="noopener noreferrer">
            {vendorName}
          </a>
        );
      },
    },
    {
        Header: 'Actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => handleEdit(row.original)}>Edit</button>
            <button onClick={() => handleDelete(row.original)}>Delete</button>
          </div>
        ),
      },
    ],
    [handleEdit, handleDelete, vendors]
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize, globalFilter },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: materials,
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );

  if (materials.length === 0) {
    return <div>Loading...</div>;
  }

  return (
    <div>
      <AddMaterial handleAdd={handleAdd} vendors={vendors} />
      <div className="search">
        <input
          type="text"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search..."
        />
      </div>
      <table {...getTableProps()} className="material-table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.getRowProps().key}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                {editingMaterial && editingMaterial.matid === row.original.matid && (
                  <tr>
                    <td colSpan={columns.length}>
                      <EditMaterial material={editingMaterial} handleUpdate={handleUpdate} />
                    </td>
                  </tr>
                )}
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          Page{' '}
          <strong>
            {pageIndex + 1} of {Math.ceil(materials.length / pageSize)}
          </strong>{' '}
        </span>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => {
              const page = e.target.value ? Number(e.target.value) - 1 : 0;
              gotoPage(page);
            }}
            style={{ width: '50px' }}
          />
        </span>
        <select
          value={pageSize}
          onChange={(e) => {
            setPageSize(Number(e.target.value));
          }}
        >
          {[10, 25, 50].map((pageSize) => (
            <option key={pageSize} value={pageSize}>
              Show {pageSize}
            </option>
          ))}
        </select>
      </div>
      
    </div>
  );
};

export default Purchases;
